#include <bits/stdc++.h>
#define int long long
using namespace std;
int m , n , ans;
int dp[10005] , a[105][2005];
signed main() {
    cin >> n >> m >> ans;
    for( int i = 1 ; i <= n ; i++ ) {
        for( int j = 1 ; j <= m ; j++ ) {
            cin >> a[i][j];
        }
    }
    for( int i = 2 ; i <= n ; i++ ) {
        memset( dp , 0 , sizeof( dp ) );
        for( int j = 1 ; j <= m ; j++ ) {
            for( int k = a[i - 1][j] ; k <= ans ; k++ ) {
                dp[k] = max( dp[k] , dp[k - a[i - 1][j]] + a[i][j] - a[i - 1][j] );
            }
        }
        ans += dp[ans];
    }
    cout << ans;
    return 0;
}
